evaluators.evaluation_logic:
const checkpoints = [];

const filterParams = JSON.parse(localStorage.getItem('task1_filterParams') || 'null');
const talents = JSON.parse(localStorage.getItem('talent_profiles') || '[]');
const lists = JSON.parse(localStorage.getItem('talent_lists') || '[]');
const items = JSON.parse(localStorage.getItem('talent_list_items') || '[]');
const availability = JSON.parse(localStorage.getItem('talent_availability_slots') || '[]');

function isQualifyingTalentBase(talent) {
  if (!talent || talent.profile_status !== 'active') return false;
  if (talent.talent_role !== 'model') return false;
  if (talent.gender !== 'female') return false;
  const loc = (talent.location_display || '').toLowerCase();
  if (loc !== 'new york, ny') return false;
  const cat = (talent.primary_category || '').toLowerCase();
  if (cat !== 'fashion model') return false;
  if (typeof talent.hourly_rate !== 'number' || talent.hourly_rate > 150) return false;
  if (typeof talent.rating_overall !== 'number' || talent.rating_overall < 4.5) return false;
  return true;
}

function isSeptember2026(dateStr) {
  if (!dateStr) return false;
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return false;
  return d.getUTCFullYear() === 2026 && d.getUTCMonth() === 8; // September
}

const shortlist = lists.find(l => l && l.list_type === 'shortlist' && l.is_default);
let shortlistEntries = [];
if (shortlist) {
  const shortlistItems = items.filter(li => li.list_id === shortlist.id);
  shortlistEntries = shortlistItems.map(li => {
    const talent = talents.find(t => t.id === li.talent_id);
    return { listItem: li, talent };
  });
}

const baseQualifying = shortlistEntries.filter(e => isQualifyingTalentBase(e.talent));

const qualifyingWithDateAndAvailability = baseQualifying.filter(e => {
  const li = e.listItem;
  const talent = e.talent;
  if (!li || !talent) return false;
  const selDate = li.selected_date;
  if (!isSeptember2026(selDate)) return false;
  const targetTime = new Date(selDate).getTime();
  const hasAvail = availability.some(a => {
    if (!a || a.talent_id !== talent.id || !a.is_available) return false;
    const ad = new Date(a.date);
    return !isNaN(ad.getTime()) && ad.getTime() === targetTime;
  });
  return hasAvail;
});

// CP1 (0.35): User used correct search filters for this task.
const cp1Passed = !!(filterParams && typeof filterParams === 'object' &&
  (filterParams.location || '').toLowerCase() === 'new york, ny' &&
  (filterParams.primary_category || '').toLowerCase() === 'fashion model' &&
  filterParams.gender === 'female' &&
  typeof filterParams.max_hourly_rate === 'number' && filterParams.max_hourly_rate <= 150 &&
  typeof filterParams.min_rating === 'number' && filterParams.min_rating >= 4.5
);
checkpoints.push({ passed: cp1Passed, weight: 0.35 });

// CP2 (0.35): At least one default-shortlist entry where the talent meets all non-date criteria.
checkpoints.push({ passed: baseQualifying.length >= 1, weight: 0.35 });

// CP3 (0.30): At least one such shortlisted talent is selected for an available day in September 2026.
checkpoints.push({ passed: qualifyingWithDateAndAvailability.length >= 1, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const castingCalls = JSON.parse(localStorage.getItem('casting_calls') || '[]');

const laMaleFitness = castingCalls.filter(c => {
  if (!c) return false;
  const loc = (c.location_display || '').toLowerCase();
  const cat = (c.talent_category || '').toLowerCase();
  return loc === 'los angeles, ca' &&
    c.talent_role === 'model' &&
    cat === 'fitness model' &&
    c.gender === 'male';
});

const laMaleFitnessWithRateAndDate = laMaleFitness.filter(c => {
  if (c.rate_type !== 'per_hour') return false;
  if (typeof c.rate_amount !== 'number' || c.rate_amount > 100) return false;
  const d = c.project_date ? new Date(c.project_date) : null;
  if (!d || isNaN(d.getTime())) return false;
  return d.getUTCFullYear() === 2026 && d.getUTCMonth() === 9; // October
});

const publishedQualified = laMaleFitnessWithRateAndDate.filter(c => c.status === 'published');

// CP1 (0.50): At least one LA casting targeting male fitness models needing >=3 talents.
const cp1Passed = laMaleFitness.some(c => typeof c.num_talent_needed === 'number' && c.num_talent_needed >= 3);
checkpoints.push({ passed: cp1Passed, weight: 0.50 });

// CP2 (0.50): At least one such casting is published, per-hour, <=$100/hr, in October 2026, and needs >=3 talents.
const cp2Passed = publishedQualified.some(c => typeof c.num_talent_needed === 'number' && c.num_talent_needed >= 3);
checkpoints.push({ passed: cp2Passed, weight: 0.50 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const talents = JSON.parse(localStorage.getItem('talent_profiles') || '[]');
const slots = JSON.parse(localStorage.getItem('talent_availability_slots') || '[]');
const currentTalentId = localStorage.getItem('current_talent_id') || '';

const me = talents.find(t => t.id === currentTalentId);

// CP1 (0.50): Current profile is a Chicago-based fashion model with at least two languages.
let cp1Passed = false;
if (me) {
  const loc = (me.location_display || '').toLowerCase();
  const cat = (me.primary_category || '').toLowerCase();
  const langCount = Array.isArray(me.languages) ? me.languages.length : 0;
  if (loc === 'chicago, il' &&
      me.talent_role === 'model' &&
      cat === 'fashion model' &&
      langCount >= 2) {
    cp1Passed = true;
  }
}
checkpoints.push({ passed: cp1Passed, weight: 0.50 });

// CP2 (0.50): This profile has at least one pair of consecutive available days in November 2026.
let cp2Passed = false;
if (me) {
  const mySlots = slots.filter(s => s.talent_id === me.id && s.is_available);
  const novDates = mySlots
    .map(s => new Date(s.date))
    .filter(d => !isNaN(d.getTime()) && d.getUTCFullYear() === 2026 && d.getUTCMonth() === 10); // November
  novDates.sort((a, b) => a - b);
  for (let i = 0; i < novDates.length - 1; i++) {
    const d1 = novDates[i];
    const d2 = novDates[i + 1];
    const diffDays = (d2 - d1) / (1000 * 60 * 60 * 24);
    if (diffDays === 1) {
      cp2Passed = true;
      break;
    }
  }
}
checkpoints.push({ passed: cp2Passed, weight: 0.50 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const instrument = JSON.parse(localStorage.getItem('task4_comparedTalentIds') || 'null');
const talents = JSON.parse(localStorage.getItem('talent_profiles') || '[]');
const lists = JSON.parse(localStorage.getItem('talent_lists') || '[]');
const items = JSON.parse(localStorage.getItem('talent_list_items') || '[]');
const bookings = JSON.parse(localStorage.getItem('booking_requests') || '[]');

const shortlist = lists.find(l => l && l.list_type === 'shortlist' && l.is_default);
let comparedQualifying = [];

if (instrument && Array.isArray(instrument.ids) && shortlist) {
  const uniqueIds = Array.from(new Set(instrument.ids));
  comparedQualifying = uniqueIds
    .map(id => {
      const talent = talents.find(t => t.id === id);
      if (!talent) return null;
      const inShortlist = items.some(li => li.list_id === shortlist.id && li.talent_id === id);
      const hourlyOk = typeof talent.hourly_rate === 'number' && talent.hourly_rate <= 150;
      const active = talent.profile_status === 'active';
      return inShortlist && hourlyOk && active ? talent : null;
    })
    .filter(Boolean);
}

// CP1 (0.30): User compared at least two shortlist models that are active and charge <= $150/hr.
const cp1Passed = comparedQualifying.length >= 2;
checkpoints.push({ passed: cp1Passed, weight: 0.30 });

// Find a booking that matches one of these compared talents, in Dec 2026, 4 hours, total_cost <= 600.
let qualifyingBooking = null;
if (Array.isArray(bookings) && comparedQualifying.length > 0) {
  const comparedIds = new Set(comparedQualifying.map(t => t.id));
  qualifyingBooking = bookings.find(b => {
    if (!b || !comparedIds.has(b.talent_id)) return false;
    if (typeof b.duration_hours !== 'number' || b.duration_hours !== 4) return false;
    if (typeof b.total_cost !== 'number' || b.total_cost > 600) return false;
    const d = b.booking_date ? new Date(b.booking_date) : null;
    if (!d || isNaN(d.getTime())) return false;
    if (d.getUTCFullYear() !== 2026 || d.getUTCMonth() !== 11) return false; // December
    const talent = talents.find(t => t.id === b.talent_id);
    if (!talent) return false;
    if (typeof talent.hourly_rate === 'number' && typeof b.hourly_rate_snapshot === 'number' && b.hourly_rate_snapshot !== talent.hourly_rate) return false;
    return true;
  }) || null;
}

// CP2 (0.30): A valid December 2026, 4-hour, <=$600 booking exists for one of the compared qualifying models.
const cp2Passed = !!qualifyingBooking;
checkpoints.push({ passed: cp2Passed, weight: 0.30 });

// CP3 (0.40): The booked model has the highest social reach among all compared qualifying models.
let cp3Passed = false;
if (qualifyingBooking && comparedQualifying.length > 0) {
  const sortedByReach = comparedQualifying.slice().sort((a, b) => {
    const ar = typeof a.social_reach_total === 'number' ? a.social_reach_total : 0;
    const br = typeof b.social_reach_total === 'number' ? b.social_reach_total : 0;
    return br - ar;
  });
  const top = sortedByReach[0];
  if (top && top.id === qualifyingBooking.talent_id) {
    cp3Passed = true;
  }
}
checkpoints.push({ passed: cp3Passed, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const talents = JSON.parse(localStorage.getItem('talent_profiles') || '[]');
const lists = JSON.parse(localStorage.getItem('talent_lists') || '[]');
const items = JSON.parse(localStorage.getItem('talent_list_items') || '[]');

function isMiamiModelInRange(talent) {
  if (!talent) return false;
  if (talent.talent_role !== 'model') return false;
  const loc = (talent.location_display || '').toLowerCase();
  if (loc !== 'miami, fl') return false;
  if (typeof talent.age !== 'number' || talent.age < 20 || talent.age > 30) return false;
  if (talent.gender !== 'female' && talent.gender !== 'male') return false;
  return true;
}

const favoriteLists = lists.filter(l => l && l.list_type === 'favorites_list');

let hasListWith2f2m = false;
let hasPureMiamiList = false;

favoriteLists.forEach(list => {
  const listItems = items.filter(li => li.list_id === list.id);
  const talentsForList = listItems
    .map(li => talents.find(t => t.id === li.talent_id))
    .filter(Boolean);

  const qualifying = talentsForList.filter(isMiamiModelInRange);
  const femaleCount = qualifying.filter(t => t.gender === 'female').length;
  const maleCount = qualifying.filter(t => t.gender === 'male').length;

  if (femaleCount >= 2 && maleCount >= 2) {
    hasListWith2f2m = true;
    const allQualifying = talentsForList.length > 0 && talentsForList.every(t => isMiamiModelInRange(t));
    if (allQualifying) {
      hasPureMiamiList = true;
    }
  }
});

// CP1 (0.60): At least one favorites list has >=2 female and >=2 male Miami models aged 20–30.
checkpoints.push({ passed: hasListWith2f2m, weight: 0.60 });

// CP2 (0.40): At least one favorites list is composed entirely of qualifying Miami models in this age range.
checkpoints.push({ passed: hasPureMiamiList, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const searchParams = JSON.parse(localStorage.getItem('task6_searchParams') || 'null');
const firstResultsObj = JSON.parse(localStorage.getItem('task6_firstResultIds') || 'null');
const talents = JSON.parse(localStorage.getItem('talent_profiles') || '[]');
const messages = JSON.parse(localStorage.getItem('messages') || '[]');

function isQualifyingTalent(talent) {
  if (!talent || talent.profile_status !== 'active') return false;
  const loc = (talent.location_display || '').toLowerCase();
  const cat = (talent.primary_category || '').toLowerCase();
  if (loc !== 'los angeles, ca') return false;
  if (cat !== 'commercial actor') return false;
  const langs = Array.isArray(talent.languages) ? talent.languages.map(l => l.toLowerCase()) : [];
  if (!langs.includes('english') || !langs.includes('spanish')) return false;
  if (typeof talent.rating_overall !== 'number' || talent.rating_overall < 4.0) return false;
  return true;
}

const targetIds = firstResultsObj && Array.isArray(firstResultsObj.ids) ? Array.from(new Set(firstResultsObj.ids)) : [];

// CP1 (0.40): Search used correct filters: LA, Commercial Actor, languages_all includes English & Spanish, min_rating >= 4.0.
let cp1Passed = false;
if (searchParams && typeof searchParams === 'object') {
  const loc = (searchParams.location || '').toLowerCase();
  const cat = (searchParams.primary_category || '').toLowerCase();
  const langsAll = Array.isArray(searchParams.languages_all) ? searchParams.languages_all.map(l => l.toLowerCase()) : [];
  const hasEnglish = langsAll.includes('english');
  const hasSpanish = langsAll.includes('spanish');
  const minRatingOk = typeof searchParams.min_rating === 'number' && searchParams.min_rating >= 4.0;
  cp1Passed = loc === 'los angeles, ca' && cat === 'commercial actor' && hasEnglish && hasSpanish && minRatingOk;
}
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

// CP2 (0.60): All tracked first-result IDs are qualifying, and at least one sent message includes all of them as recipients.
let cp2Passed = false;
if (targetIds.length > 0) {
  const allTargetsQualify = targetIds.every(id => {
    const t = talents.find(tt => tt.id === id);
    return isQualifyingTalent(t);
  });

  const hasMessage = messages.some(m => {
    if (!m || m.sender_role !== 'client') return false;
    const recips = Array.isArray(m.recipient_talent_ids) ? m.recipient_talent_ids : [];
    return targetIds.every(id => recips.includes(id));
  });

  cp2Passed = allTargetsQualify && hasMessage;
}
checkpoints.push({ passed: cp2Passed, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const plans = JSON.parse(localStorage.getItem('subscription_plans') || '[]');
const sessions = JSON.parse(localStorage.getItem('subscription_checkout_sessions') || '[]');

const basicMonthlyPlans = plans.filter(p => {
  if (!p) return false;
  return p.plan_type === 'talent_scouting' &&
    p.plan_tier === 'basic' &&
    p.supports_monthly_billing &&
    typeof p.price_monthly === 'number' && p.price_monthly <= 100;
});

let cheapestPlan = null;
if (basicMonthlyPlans.length > 0) {
  cheapestPlan = basicMonthlyPlans.reduce((min, p) => {
    if (!min) return p;
    return p.price_monthly < min.price_monthly ? p : min;
  }, null);
}

const reviewSessions = sessions.filter(s => s && s.status === 'review' && s.billing_frequency === 'monthly');

const reviewForBasicMonthly = reviewSessions.filter(s => {
  const plan = plans.find(p => p.id === s.plan_id);
  if (!plan) return false;
  return plan.plan_type === 'talent_scouting' &&
    plan.plan_tier === 'basic' &&
    plan.supports_monthly_billing &&
    typeof plan.price_monthly === 'number' && plan.price_monthly <= 100;
});

// CP1 (0.40): User reached review for at least one qualifying Basic monthly talent-scouting plan.
const cp1Passed = reviewForBasicMonthly.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

// CP2 (0.60): At least one such review session is for the cheapest qualifying Basic monthly plan.
let cp2Passed = false;
if (cheapestPlan) {
  cp2Passed = reviewForBasicMonthly.some(s => s.plan_id === cheapestPlan.id);
}
checkpoints.push({ passed: cp2Passed, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const events = JSON.parse(localStorage.getItem('events') || '[]');
const regs = JSON.parse(localStorage.getItem('event_registrations') || '[]');

const startAfter = new Date('2026-08-01T00:00:00Z');

const candidates = events.filter(e => {
  if (!e || !e.is_published) return false;
  const loc = (e.location_display || '').toLowerCase();
  const cat = (e.category || '').toLowerCase();
  if (e.event_type !== 'workshop') return false;
  if (loc !== 'new york, ny') return false;
  if (cat !== 'intro to modeling') return false;
  const d = e.start_datetime ? new Date(e.start_datetime) : null;
  if (!d || isNaN(d.getTime())) return false;
  return d > startAfter;
});

let earliestEvent = null;
if (candidates.length > 0) {
  earliestEvent = candidates.reduce((min, e) => {
    const d = new Date(e.start_datetime);
    if (!min) return e;
    const md = new Date(min.start_datetime);
    return d < md ? e : min;
  }, null);
}

let registrationForEarliest = null;
if (earliestEvent) {
  registrationForEarliest = regs.find(r => r && r.event_id === earliestEvent.id && r.seats_reserved === 2) || null;
}

// CP1 (0.50): There is a registration for the earliest qualifying NY Intro to Modeling workshop with exactly 2 seats reserved.
const cp1Passed = !!registrationForEarliest;
checkpoints.push({ passed: cp1Passed, weight: 0.50 });

// CP2 (0.50): That registration uses a pay-on-site or pay-later style option (not immediate online payment).
let cp2Passed = false;
if (registrationForEarliest) {
  const opt = registrationForEarliest.payment_option;
  cp2Passed = opt === 'pay_on_site' || opt === 'pay_later';
}
checkpoints.push({ passed: cp2Passed, weight: 0.50 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
